<template>
  <article class="page">
    <span class="page-orn po1"
      ><svg viewBox="0 0 24 24"><path d="M2 12c6 0 10-4 10-10 0 6 4 10 10 10-6 0-10 4-10 10 0-6-4-10-10-10z" /></svg
    ></span>
    <span class="page-orn po2"
      ><svg viewBox="0 0 24 24"><path d="M2 12c6 0 10-4 10-10 0 6 4 10 10 10-6 0-10 4-10 10 0-6-4-10-10-10z" /></svg
    ></span>
    <span class="page-orn po3"
      ><svg viewBox="0 0 24 24"><path d="M2 12c6 0 10-4 10-10 0 6 4 10 10 10-6 0-10 4-10 10 0-6-4-10-10-10z" /></svg
    ></span>
    <span class="page-orn po4"
      ><svg viewBox="0 0 24 24"><path d="M2 12c6 0 10-4 10-10 0 6 4 10 10 10-6 0-10 4-10 10 0-6-4-10-10-10z" /></svg
    ></span>

    <div class="paper-head">
      <h2>购物 <span class="star">✦</span></h2>
    </div>
    <div class="paper-body">
      <p class="tagline">铜板与铂币的流转，从一只篮子开始。</p>

      <div class="shop-tabs" role="tablist">
        <button
          v-for="(shop, id) in shops"
          :key="id"
          type="button"
          class="shop-tab"
          :class="{ active: currentShop === id }"
          @click="currentShop = id"
          role="tab"
        >
          {{ (shop['描述'] || id).slice(0, 12) }}
        </button>
      </div>

      <div class="shop-grid">
        <section class="shop-products-wrap">
          <h3 class="shop-h3">货品</h3>
          <div class="shop-products">
            <button
              v-for="(item, name) in currentItems"
              :key="name"
              type="button"
              class="shop-product"
              :data-in-cart="isInCart(name) ? '1' : '0'"
              @click="addToCart(name)"
            >
              <span v-if="isInCart(name)" class="shop-product-badge">×{{ cartQty(name) }}</span>
              <div class="shop-product-name">{{ name }}</div>
              <div class="shop-product-meta">
                <span class="shop-product-cat">{{ item['分类'] || '其他' }}</span>
                <span class="shop-product-price"
                  >{{ fmtCopper(item['单价铜币'] ?? 0) }} / {{ item['单位'] || '份' }}</span
                >
              </div>
              <div v-if="item['备注']" class="shop-product-note">{{ item['备注'] }}</div>
            </button>
          </div>
        </section>

        <aside class="shop-cart-wrap">
          <h3 class="shop-h3">
            购物篮 <span class="shop-h3-sub">{{ cartTotalQty }} 件</span>
          </h3>
          <div class="shop-cart">
            <div v-for="(line, key) in cart" :key="key" class="cart-line">
              <div>
                <div class="cart-line-name">{{ line.itemName }}</div>
              </div>
              <div class="cart-line-price">
                {{ fmtCopper(line.price) }} × {{ line.qty }}<br /><b>= {{ fmtCopper(line.qty * line.price) }}</b>
              </div>
              <div class="cart-line-ctrl">
                <button type="button" class="cart-step" @click="decCart(key)">−</button>
                <span class="cart-qty">{{ line.qty }} {{ line.unit }}</span>
                <button type="button" class="cart-step" @click="incCart(key)">+</button>
                <button type="button" class="cart-line-rm" @click="rmCart(key)">移除</button>
              </div>
            </div>
            <p v-if="!Object.keys(cart).length" class="shop-cart-empty">点商品名加入篮子。</p>
          </div>
          <div class="shop-cart-foot">
            <div class="shop-total">
              <span class="shop-total-k">合计</span>
              <span class="shop-total-v">{{ fmtCopper(cartTotal) }}</span>
            </div>
            <div class="shop-cart-actions">
              <button type="button" class="inv-act-btn shop-pay-btn" @click="checkout">🧾 结账并入库</button>
              <button type="button" class="inv-clear" @click="clearCart">清空购物篮</button>
            </div>
          </div>
        </aside>
