<script setup lang="ts">
import { ref, computed, inject } from 'vue';

const store = inject('store') as any;
const data = computed(() => store?.data ?? {});
const shops = computed(() => ((data.value as any)['购物'] || {})['店铺列表'] || {});

const currentShop = ref(Object.keys(shops.value)[0] || '');
const cart = ref<Record<string, { shopId: string; itemName: string; qty: number; price: number; unit: string }>>({});

const currentItems = computed(() => {
  const shop = shops.value[currentShop.value];
  return (shop && shop['商品列表']) || {};
});

function cartKey(name: string) {
  return `${currentShop.value}::${name}`;
}
function isInCart(name: string) {
  return !!cart.value[cartKey(name)];
}
function cartQty(name: string) {
  return cart.value[cartKey(name)]?.qty || 0;
}

function addToCart(name: string) {
  const k = cartKey(name);
  if (cart.value[k]) {
    cart.value[k].qty++;
  } else {
    const item = currentItems.value[name];
    if (!item) return;
    cart.value[k] = {
      shopId: currentShop.value,
      itemName: name,
      qty: 1,
      price: item['单价铜币'] ?? 0,
      unit: item['单位'] || '份',
    };
  }
}

function incCart(k: string) {
  if (cart.value[k]) cart.value[k].qty++;
}
function decCart(k: string) {
  if (!cart.value[k]) return;
  cart.value[k].qty--;
  if (cart.value[k].qty <= 0) delete cart.value[k];
}
function rmCart(k: string) {
  delete cart.value[k];
}
function clearCart() {
  cart.value = {};
}

const cartTotalQty = computed(() => Object.values(cart.value).reduce((a, l) => a + l.qty, 0));
const cartTotal = computed(() => Object.values(cart.value).reduce((a, l) => a + l.qty * l.price, 0));

const COIN_TIERS = [
  { name: '秘银', value: 250_000_000 },
  { name: '铂', value: 500_000 },
  { name: '金', value: 1_000 },
  { name: '银', value: 100 },
  { name: '铜', value: 1 },
] as const;

function fmtCopper(total: number): string {
  if (!total || total <= 0) return '0铜';
  let rem = total;
  const parts: string[] = [];
  for (const tier of COIN_TIERS) {
    const c = Math.floor(rem / tier.value);
    if (c > 0) {
      parts.push(`${c}${tier.name}`);
      rem -= c * tier.value;
    }
  }
  return parts.join(' ');
}

function checkout() {
  const lines = Object.values(cart.value);
  if (!lines.length) {
    const out = document.getElementById('globalOutput') as HTMLTextAreaElement | null;
    if (out) out.value = '购物篮是空的。';
    return;
  }
  let total = 0;
  const rows = lines
    .map(l => {
      const sub = l.qty * l.price;
      total += sub;
      return `- ${l.itemName} ×${l.qty}${l.unit} @ ${fmtCopper(l.price)}/${l.unit} = ${fmtCopper(sub)}`;
    })
    .join('\n');
  const out = document.getElementById('globalOutput') as HTMLTextAreaElement | null;
  if (out) out.value = `[购物清单]\n${rows}\n\n合计支出：${fmtCopper(total)}`;
}
</script>

